import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, PieChart, Pie, Cell } from 'recharts';

const API_URL = 'http://localhost:5000/api';
const api = axios.create({ baseURL: API_URL });
api.interceptors.request.use(config => {
    const token = localStorage.getItem('token');
    if (token) config.headers.Authorization = `Bearer ${token}`;
    return config;
});

const DoctorPortal = () => {
    const [activeTab, setActiveTab] = useState('cohort');
    const [cohortData, setCohortData] = useState({ totalPatients: 12543, atRiskPercentage: 14, avgRecoveryRate: 89 });
    const [generatingReport, setGeneratingReport] = useState(false);
    const [reportResult, setReportResult] = useState('');

    const [features, setFeatures] = useState([]);
    const [alerts, setAlerts] = useState([]);
    const [selectedAlertModel, setSelectedAlertModel] = useState(null);
    const [error, setError] = useState('');

    useEffect(() => {
        // Fetch Cohort
        api.get('/doctor/cohort').then(res => {
            if (res.data.success) {
                setCohortData({
                    totalPatients: res.data.totalPatients,
                    atRiskPercentage: res.data.atRiskPercentage,
                    avgRecoveryRate: res.data.avgRecoveryRate
                });
            }
        }).catch(err => {
            console.error(err);
            setError("Failed to fetch cohort data.");
        });

        // Fetch Features
        api.get('/feature-importance').then(res => {
            if(res.data.success) setFeatures(res.data.features);
        }).catch(err => console.error(err));

        // Fetch Alerts
        api.get('/doctor/alerts').then(res => {
            if(res.data.success) {
                setAlerts(res.data.data);
                if(res.data.data.length > 0) setSelectedAlertModel(res.data.data[0]);
            }
        }).catch(err => {
            console.error(err);
            setError("Failed to load predictive alerts.");
        });

    }, []);

    const generateAIReport = async () => {
        if(!selectedAlertModel) {
            setError("No patient selected for reporting");
            return;
        }

        setError('');
        setGeneratingReport(true);
        setReportResult('');
        try {
            const prompt = `As an expert AI clinician, generate a brief, professional discharge/referral summary report for the patient regarding predicted ${selectedAlertModel.predictedDisease} (Confidence: ${selectedAlertModel.confidence.toFixed(1)}%). Symptoms were: ${selectedAlertModel.symptoms.join(', ')}. Format nicely but keep it short.`;
            const res = await api.post('/chat', { message: prompt, systemPrompt: 'You are a clinical report generator AI. No conversational fluff.' });
            setReportResult(res.data.response);

            // Mark report saved in timeline
            setReportHistory(prev => [{
                date: new Date().toLocaleString(),
                desc: `Report Generated & Sent parameters for ${selectedAlertModel.predictedDisease}`
            }, ...prev]);

        } catch (error) {
            setReportResult("Failed to generate AI report. Check Gemini API key.");
            setError("AI Report Generation failed.");
        } finally {
            setGeneratingReport(false);
        }
    };

    // Fake Report History based on dynamic actions
    const [reportHistory, setReportHistory] = useState([
        { date: "Yesterday, 14:20 PM", desc: "Routine discharge summary generated." }
    ]);

    const COLORS = ['#ef4444', '#10b981', '#3b82f6'];
    const pieData = [
        { name: 'High Risk', value: cohortData.atRiskPercentage },
        { name: 'Low Risk', value: 100 - cohortData.atRiskPercentage }
    ];

    return (
        <div className="portal-container slide-up">
            <div className="portal-sidebar">
                <h3 className="gradient-text" style={{ padding: '0 1rem', marginBottom: '1rem' }}>Clinician Tools</h3>
                <button className={`portal-sidebar-btn ${activeTab === 'cohort' ? 'active' : ''}`} onClick={() => setActiveTab('cohort')}>👥 Cohort Analyzer</button>
                <button className={`portal-sidebar-btn ${activeTab === 'interpretability' ? 'active' : ''}`} onClick={() => setActiveTab('interpretability')}>🧠 Model Overview</button>
                <button className={`portal-sidebar-btn ${activeTab === 'reporting' ? 'active' : ''}`} onClick={() => setActiveTab('reporting')}>📄 Auto Reporting</button>
                <button className={`portal-sidebar-btn ${activeTab === 'pathways' ? 'active' : ''}`} onClick={() => setActiveTab('pathways')}>🛤️ Diagnostic Pathways</button>
                <button className={`portal-sidebar-btn ${activeTab === 'alerts' ? 'active' : ''}`} onClick={() => setActiveTab('alerts')}>🚨 Predictive Alerts</button>
            </div>

            <div className="portal-content">
                {error && <div className="error" style={{ marginBottom: '1.5rem', marginInline: '1rem' }}>{error}</div>}

                {activeTab === 'cohort' && (
                    <div className="portal-panel">
                        <h2>Patient Cohort Analyzer</h2>
                        <p className="subtitle">Live database statistics across active clinics.</p>
                        <div className="data-grid">
                            <div className="data-card">
                                <span className="data-label">Total Patients analyzed</span>
                                <span className="data-value">{cohortData.totalPatients}</span>
                            </div>
                            <div className="data-card">
                                <span className="data-label">At-Risk Group (High)</span>
                                <span className="data-value" style={{color: '#ef4444'}}>{cohortData.atRiskPercentage}%</span>
                            </div>
                            <div className="data-card">
                                <span className="data-label">Avg. Recovery Rate</span>
                                <span className="data-value" style={{color: '#10b981'}}>{cohortData.avgRecoveryRate}%</span>
                            </div>
                        </div>
                        <div style={{ height: '300px', width: '100%', marginTop: '2rem', display:'flex', justifyContent:'center'}}>
                            <ResponsiveContainer width="100%" height="100%">
                                <PieChart>
                                    <Pie data={pieData} cx="50%" cy="50%" innerRadius={80} outerRadius={120} paddingAngle={5} dataKey="value" startAngle={180} endAngle={0}>
                                        {pieData.map((entry, index) => <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />)}
                                    </Pie>
                                    <Tooltip />
                                </PieChart>
                            </ResponsiveContainer>
                        </div>
                    </div>
                )}

                {activeTab === 'interpretability' && (
                    <div className="portal-panel">
                        <h2>Model Interpretability</h2>
                        <p className="subtitle">Real-time Random Forest Feature Importance (Live ML Weights)</p>

                        <div style={{ height: '400px', width: '100%', marginTop: '2rem', background: '#f8fafc', padding: '1.5rem', borderRadius: '12px' }}>
                            {features.length > 0 ? (
                                <ResponsiveContainer width="100%" height="100%">
                                    <BarChart data={features} layout="vertical" margin={{top: 5, right: 30, left: 100, bottom: 5}}>
                                        <CartesianGrid strokeDasharray="3 3" />
                                        <XAxis type="number" />
                                        <YAxis dataKey="name" type="category" width={150} tick={{fill: '#4a5568', fontSize: 12}} />
                                        <Tooltip />
                                        <Bar dataKey="importance" fill="#667eea" radius={[0, 4, 4, 0]} />
                                    </BarChart>
                                </ResponsiveContainer>
                            ) : (
                                <div style={{display:'flex', height:'100%', alignItems:'center', justifyContent:'center', color:'#718096'}}>Loading AI model parameters...</div>
                            )}
                        </div>

                        {features.length > 0 && (
                            <div className="data-grid" style={{marginTop:'2rem'}}>
                                <div className="data-card">
                                    <span className="data-label">Top Driving Feature</span>
                                    <span className="data-value" style={{fontSize: '1.5rem'}}>{features[0].name}</span>
                                </div>
                                <div className="data-card">
                                    <span className="data-label">Impact Weight</span>
                                    <span className="data-value" style={{fontSize: '1.5rem'}}>{features[0].importance.toFixed(2)}%</span>
                                </div>
                            </div>
                        )}
                    </div>
                )}

                {activeTab === 'reporting' && (
                    <div className="portal-panel">
                        <h2>Automated Reporting and Referral</h2>
                        <p className="subtitle">Select an active high-risk case to generate dynamic summaries.</p>

                        <div style={{marginBottom:'2rem'}}>
                            <label className="data-label">Select Active Case:</label>
                            <select 
                                onChange={(e) => setSelectedAlertModel(alerts.find(a => a._id === e.target.value))}
                                style={{ width: '100%', padding: '10px', borderRadius: '8px', border: '1px solid #e2e8f0', marginTop: '0.5rem', fontFamily: 'inherit' }}
                            >
                                {alerts.map(a => (
                                    <option key={a._id} value={a._id}>Patient: {a.userId?.name || 'Unknown'} - {a.predictedDisease} ({a.confidence.toFixed(0)}%)</option>
                                ))}
                                {alerts.length === 0 && <option value="">No active high-risk patients available</option>}
                            </select>
                        </div>

                        <div className="action-card">
                            <div>
                                <h3>Generate Patient Summary</h3>
                                <p>Extracts DB history and uses Gemini Reasoning to write referral documentation.</p>
                            </div>
                            <button className="btn-secondary" style={{background: 'white', color: '#667eea', border: 'none'}} onClick={generateAIReport} disabled={generatingReport || alerts.length === 0}>
                                {generatingReport ? '⏳ Analyzing...' : '✨ Generate AI Summary'}
                            </button>
                        </div>

                        {reportResult && (
                            <div className="timeline-event" style={{marginTop: '2rem', borderLeftColor: '#667eea', background: 'white', padding: '1rem', borderRadius: '8px'}}>
                                <div className="timeline-time">AI Generated Summary for selected internal ID</div>
                                <div className="timeline-desc" style={{whiteSpace: 'pre-wrap', marginTop: '1rem', color: '#4a5568', padding:'1rem', background:'#f8fafc', border:'1px dashed #cbd5e0'}}>
                                    {reportResult}
                                </div>
                            </div>
                        )}

                        {reportHistory.map((h, i) => (
                            <div key={i} className="timeline-event" style={{marginTop: i===0 ? '2rem' : '1rem'}}>
                                <div className="timeline-time">{h.date}</div>
                                <div className="timeline-desc">
                                    <strong>Report Synced:</strong> {h.desc}
                                </div>
                            </div>
                        ))}
                    </div>
                )}

                {activeTab === 'pathways' && (
                    <div className="portal-panel">
                        <h2>Diagnostic Pathways & Treatment Suggestions</h2>
                        <p className="subtitle">Live active protocol guidance based on recent alert data.</p>
                        <div className="feature-grid">
                            {alerts.slice(0, 2).map((a, i) => (
                                <div key={i} className="data-card">
                                    <h3>Pathway: {a.predictedDisease}</h3>
                                    <p style={{marginTop:'0.5rem'}}>Status: High Risk Detected ({a.confidence.toFixed(1)}%)</p>
                                    <p style={{fontSize:'0.85rem', color:'#718096', marginTop:'0.5rem'}}>Action: Confirm diagnosis via clinical testing.</p>
                                    <div style={{width: '100%', background: '#e2e8f0', height: '10px', borderRadius: '5px', marginTop: '1rem'}}>
                                        <div style={{width: '20%', background: '#f59e0b', height: '10px', borderRadius: '5px'}}></div>
                                    </div>
                                    <button className="btn-primary" style={{marginTop: '1rem'}}>Continue Protocol</button>
                                </div>
                            ))}
                            {alerts.length === 0 && <p>No active guided pathways.</p>}
                        </div>
                    </div>
                )}

                {activeTab === 'alerts' && (
                    <div className="portal-panel">
                        <h2>Predictive Alerts & Notifications</h2>
                        <p className="subtitle">Real-time live queue of high-risk evaluations from the database.</p>

                        {alerts.length === 0 ? (
                            <div style={{padding:'2rem', textAlign:'center', color:'#718096'}}>Ward is clear. No active critical alerts.</div>
                        ) : (
                            <div style={{display: 'flex', flexDirection: 'column', gap: '1rem'}}>
                                {alerts.map(a => (
                                    <div key={a._id} className="data-card slide-up" style={{borderLeft: '5px solid #ef4444'}}>
                                        <strong>⚠️ {a.confidence >= 95 ? 'URGENT' : 'WARNING'}: {a.userId?.name || 'Unknown User'}</strong>
                                        <p style={{marginTop:'0.5rem'}}>AI detected <strong>{a.confidence.toFixed(1)}% probability</strong> of {a.predictedDisease}.</p>
                                        <span style={{fontSize:'0.8rem', color:'#a0aec0', marginTop:'0.5rem', display:'block'}}>{new Date(a.timestamp).toLocaleString()}</span>
                                    </div>
                                ))}
                            </div>
                        )}
                    </div>
                )}
            </div>
        </div>
    );
};

export default DoctorPortal;
